using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Extensions.AI;
using OpenAI;

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------
var openAiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

// ---------------------------------------------------------------------------
// Tools
// ---------------------------------------------------------------------------
var tools = new ResearchTools();

var searchTool = AIFunctionFactory.Create(tools.SearchWeb);
var addNoteTool = AIFunctionFactory.Create(tools.AddNote);
var readNotesTool = AIFunctionFactory.Create(tools.ReadNotes);

// ---------------------------------------------------------------------------
// Build the chat client with automatic function invocation
// ---------------------------------------------------------------------------
IChatClient client = new ChatClientBuilder(
        new OpenAIClient(openAiKey).GetChatClient(modelId).AsIChatClient())
    .UseFunctionInvocation()
    .Build();

var chatOptions = new ChatOptions
{
    Tools = [searchTool, addNoteTool, readNotesTool],
    ToolMode = ChatToolMode.Auto,
};

// ---------------------------------------------------------------------------
// Prompt the user for a research topic
// ---------------------------------------------------------------------------
Console.WriteLine("╔══════════════════════════════════════════╗");
Console.WriteLine("║        AI Research Agent                 ║");
Console.WriteLine("╚══════════════════════════════════════════╝");
Console.WriteLine();

Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}\n");

// ---------------------------------------------------------------------------
// Run the agent loop
// ---------------------------------------------------------------------------
List<ChatMessage> messages =
[
    new(ChatRole.System, """
        You are a research assistant. When the user gives you a topic:
        1. Use the SearchWeb tool 2-3 times with different relevant queries to
           gather information.
        2. For each useful piece of information you find, use AddNote to save it.
        3. After you have gathered enough notes, use ReadNotes to review them.
        4. Finally, produce a well-structured summary of your findings,
           organized with clear headings and bullet points.
        Be thorough but concise.
        """),
    new(ChatRole.User, $"Research the following topic and provide a summary: {topic}"),
];

var response = await client.GetResponseAsync(messages, chatOptions);

Console.WriteLine("─── Research Summary ───────────────────────\n");
Console.WriteLine(response.Text);
Console.WriteLine("\n────────────────────────────────────────────");

// ---------------------------------------------------------------------------
// Tool implementations
// ---------------------------------------------------------------------------
public class ResearchTools
{
    private static readonly HttpClient s_http = new();
    private readonly List<string> _notes = [];

    [Description("Searches the web for a given query and returns a list of result snippets. Use this to gather information about a topic.")]
    public async Task<string> SearchWeb(
        [Description("The search query string")] string query)
    {
        Console.WriteLine($"  🔍 Searching: \"{query}\"");

        try
        {
            // Use DuckDuckGo Instant Answer API (no key required)
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

            using var request = new HttpRequestMessage(HttpMethod.Get, url);
            request.Headers.UserAgent.ParseAdd("ResearchAgent/1.0");

            var resp = await s_http.SendAsync(request);
            resp.EnsureSuccessStatusCode();

            using var doc = await JsonDocument.ParseAsync(await resp.Content.ReadAsStreamAsync());
            var root = doc.RootElement;

            var results = new List<string>();

            // Abstract / main answer
            var abstractText = root.GetProperty("AbstractText").GetString();
            var abstractSource = root.GetProperty("AbstractSource").GetString();
            if (!string.IsNullOrWhiteSpace(abstractText))
                results.Add($"[{abstractSource}] {abstractText}");

            // Related topics
            if (root.TryGetProperty("RelatedTopics", out var related))
            {
                foreach (var item in related.EnumerateArray().Take(5))
                {
                    var text = item.TryGetProperty("Text", out var t) ? t.GetString() : null;
                    if (!string.IsNullOrWhiteSpace(text))
                        results.Add(text);
                }
            }

            if (results.Count == 0)
                return $"No results found for \"{query}\". Try a different search query.";

            return string.Join("\n\n", results);
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Try a different query.";
        }
    }

    [Description("Saves a research note. Use this to record key findings during research.")]
    public string AddNote(
        [Description("The note content to save")] string note)
    {
        _notes.Add(note);
        Console.WriteLine($"  📝 Note #{_notes.Count} saved");
        return $"Note #{_notes.Count} saved successfully.";
    }

    [Description("Reads all saved research notes. Use this to review what you have collected so far before writing a summary.")]
    public string ReadNotes()
    {
        Console.WriteLine($"  📖 Reading {_notes.Count} note(s)");
        if (_notes.Count == 0)
            return "No notes saved yet.";

        return string.Join("\n",
            _notes.Select((n, i) => $"Note #{i + 1}: {n}"));
    }
}

